// src/App.js
import './index.css';
import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate } from "react-router-dom";

import Header from "./components/Header";
import Sidebar from './components/Sidebar';
import TelaPeriodos from "./components/TelaPeriodos";
import TelaAlunos from "./components/TelaAlunos";
import TelaPacientes from "./components/TelaPacientes";
import TelaDisciplinas from "./components/TelaDisciplinas";
import TelaAgendamentos from "./components/TelaAgendamentos";

import Login from "./Login";
import DashboardAluno from "./DashboardAluno";
import DashboardRecepcao from "./DashboardRecepcao";
import BottomNavBar from './components/BottomNavBar';
import ProtectedRoute from './components/ProtectedRoute';
import { AuthProvider, useAuth } from './context/AuthContext';

/**
 * Componente que decide qual dashboard mostrar, com base em user.role.
 */
function Dashboards() {
  const { user } = useAuth();

  // Se o usuário tiver role="recepcao", mostra DashboardRecepcao, senão DashboardAluno.
  if (user?.role === "recepcao") {
    return <DashboardRecepcao />;
  }
  return <DashboardAluno />;
}

/**
 * LayoutInterno: header + sidebar + conteúdo principal + bottom navbar.
 */
function LayoutInterno() {
  const [active, setActive] = useState('dashboard');

  function renderConteudo() {
    switch (active) {
      case 'dashboard':
        return <Dashboards />;       // usa o componente Dashboards aqui
      case 'agendar':
        return <TelaAgendamentos />;
      case 'disciplinas':
        return <TelaDisciplinas />;
      case 'pacientes':
        return <TelaPacientes />;
      case 'alunos':
        return <TelaAlunos />;
      case 'periodos':
        return <TelaPeriodos />;
      default:
        return (
          <div>
            <h1 className="text-3xl font-bold mb-6">Página não encontrada</h1>
          </div>
        );
    }
  }

  return (
    <div className="bg-[#ffffff] min-h-screen">
      <Header />
      <div className="flex">
        {/* Sidebar (somente em md+) */}
        <div className="hidden md:block">
          <Sidebar active={active} onMenuClick={setActive} />
        </div>
        <main className="flex-1 ml-0 md:ml-64 mt-16 p-8 h-[calc(100vh-64px)] overflow-y-auto">
          <div className="mx-auto">{renderConteudo()}</div>
        </main>
      </div>
      {/* BottomNavBar (somente em mobile) */}
      <BottomNavBar active={active} onMenuClick={setActive} />
    </div>
  );
}

/**
 * LoginWrapper: pega o login() do AuthContext e passa como prop para <Login />.
 * Depois que o login() for chamado, redireciona para a rota "/" (área interna).
 */
function LoginWrapper() {
  const { login } = useAuth();
  const navigate = useNavigate();

  // Este onLogin será passado ao componente <Login onLogin={onLogin} />
  function onLoginHandler(dadosDoLogin) {
    // dadosDoLogin = { role, token, usuario }  
    // note que em Login.js fazemos: onLogin(res.data)
    // onde res.data === { token, usuario, role }

    login(dadosDoLogin);
    // Uma vez logado (login() salvou no localStorage e atualizou o user),
    // redirecionamos para a rota principal:
    navigate("/", { replace: true });
  }

  return <Login onLogin={onLoginHandler} />;
}

/**
 * App: provê AuthProvider, define nossas rotas e envolve LayoutInterno em ProtectedRoute.
 */
export default function App() {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          {/* Rota pública: /login */}
          <Route path="/login" element={<LoginWrapper />} />

          {/* Toda a “/*” (demais rotas) fica protegida por ProtectedRoute */}
          <Route
            path="/*"
            element={
              <ProtectedRoute>
                <LayoutInterno />
              </ProtectedRoute>
            }
          />

          {/* Qualquer rota desconhecida redireciona para /login */}
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}
